1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	interface Item {
15	  type: string;
16	  cursed?: boolean;
17	  enchantment?: number;
18	  material?: string;
19	}
20	
21	interface Step {
22	  op: string;
23	  items?: Item[];
24	}
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BLOCK_SIZE = 3;
32	const BLOCK_PREMIUM = 60;
33	const CURSE_SURCHARGE_PERCENT = 50;
34	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const LOYALTY_DISCOUNT_PERCENT = 20;
37	const LOYALTY_THRESHOLD_YEARS = 2;
38	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
39	
40	interface Customer {
41	  yearsWithMHPCO: number;
42	}
43	
44	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
45	
46	const percentOf = (amount: number, percent: number): number =>
47	  (amount * percent) / PERCENT_BASE;
48	
49	const surchargeIf = (condition: boolean, base: number, percent: number): number =>
50	  condition ? percentOf(base, percent) : 0;
51	
52	const itemBasePremium = (item: Item): number => {
53	  const base = BASE_PREMIUM[item.type];
54	  const curse = surchargeIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
55	  const highEnchantment = surchargeIf(
56	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
57	    base,
58	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
59	  );
60	  return base + curse + highEnchantment;
61	};
62	
63	const sumBase = (items: Item[]): number =>
64	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
65	
66	const partitionByType = (items: Item[]): Item[][] => {
67	  const groups: Record<string, Item[]> = {};
68	  items.forEach((item) => (groups[item.type] ??= []).push(item));
69	  return Object.values(groups);
70	};
71	
72	const priceGroup = (group: Item[]): number =>
73	  group.length === BLOCK_SIZE && isComponent(group[0])
74	    ? BLOCK_PREMIUM
75	    : sumBase(group);
76	
77	const sumBasePremiums = (items: Item[]): number =>
78	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
79	
80	const applyPolicyModifiers = (base: number, customer: Customer): number => {
81	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
82	  const loyalty =
83	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
84	      ? percentOf(base, LOYALTY_DISCOUNT_PERCENT)
85	      : 0;
86	  return base + firstInsurance - loyalty;
87	};
88	
89	const quotePremium = (items: Item[], customer: Customer): number =>
90	  Math.ceil(applyPolicyModifiers(sumBasePremiums(items), customer)) + PROCESSING_FEE;
91	
92	const executeStep = (step: Step, customer: Customer): { premium: number } => ({
93	  premium: quotePremium(step.items ?? [], customer),
94	});
95	
96	export const runScenario = (input: unknown): { results: unknown[] } => {
97	  const scenario = input as Scenario;
98	  return {
99	    results: scenario.steps.map((step) => executeStep(step, scenario.customer)),
100	  };
101	};
